<?php
/** Driver update page; employee ID remains immutable after onboarding. */
declare(strict_types=1);
require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/driver_functions.php';requireAuth();enforceModuleAccess('drivers');$id=(int)($_GET['id']??$_POST['id']??0);$driver=getDriverById($id);if(!$driver){setFlash('danger','Driver not found.');redirect('modules/drivers/index.php');}if($_SERVER['REQUEST_METHOD']==='POST'){if(!verifyCsrfToken((string)($_POST['csrf_token']??''))){setFlash('danger','Invalid form token.');redirect('modules/drivers/edit.php?id='.$id);}[$ok,$result]=saveDriver($_POST,$id);setFlash($ok?'success':'danger',$ok?'Driver updated.':implode(' ',(array)$result));redirect($ok?'modules/drivers/view.php?id='.$id:'modules/drivers/edit.php?id='.$id);} $regions=getDb()->query('SELECT id,name FROM regions ORDER BY name')->fetchAll();$pageTitle='Edit driver';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content driver-module"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-heading page-section"><div><h1 class="page-title">Edit <?=e($driver['full_name'])?></h1><p class="page-subtitle">Employee ID is retained; license changes are audited through this secure form.</p></div></section><form class="card dashboard-card driver-form" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="id" value="<?=$id?>"><div class="form-grid"><?php foreach(['full_name'=>'Full name','email'=>'Email','phone'=>'Phone','license_number'=>'License number','license_expiry'=>'License expiry','license_category'=>'License category','experience_years'=>'Experience','safety_score'=>'Safety score','medical_certificate_expiry'=>'Medical expiry'] as $field=>$label):?><div class="form-group"><label><?=e($label)?></label><input name="<?=$field?>" type="<?=str_contains($field,'expiry')?'date':'text'?>" value="<?=e((string)$driver[$field])?>" <?=in_array($field,['full_name','email','phone','license_number','license_expiry'],true)?'required':''?>></div><?php endforeach;?><div class="form-group"><label>Region</label><select name="region_id"><?php foreach($regions as $region):?><option value="<?=$region['id']?>"<?=$driver['region_id']==$region['id']?' selected':''?>><?=e($region['name'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Status</label><select name="status"><?php foreach(['Available','Off Duty','Suspended','Inactive'] as $status):?><option<?=$driver['status']===$status?' selected':''?>><?=$status?></option><?php endforeach;?></select></div></div><div class="form-group"><label>Remarks</label><textarea name="remarks"><?=e((string)$driver['remarks'])?></textarea></div><div class="form-actions"><button class="btn btn-primary">Save changes</button><a class="btn btn-secondary" href="view.php?id=<?=$id?>">Cancel</a></div></form></main><?php require ROOT_PATH.'/includes/footer.php';?>
